/**
 * RESOLVE_PRIMARY_ITEM — FINAL (WORKFLOW 3 SAFE)
 *
 * Resolves primary item ONLY if the selected item
 * is a true entrée. Side-only passes skip resolution.
 */

const input = $json;

// ✅ Explicit entrée whitelist (no guessing)
const ENTREES = [
  "PHILLY",
  "COWBOY",
  "CLUB",
  "FRIED",
  "ROCKTOWN_SLIDERS",
];

// ✅ Validate item_id exists
if (typeof input.item_id !== "string" || input.item_id.trim() === "") {
  throw new Error("Missing item_id");
}

// ✅ Side‑only pass → skip primary resolution
if (!ENTREES.includes(input.item_id)) {
  return {
    ...input,
    selected_item_id: null,
    primary_item: null,
    primary_item_resolved_at: null,
  };
}

/* ─────────────────────────────────────────────
 * IDENTITY LATCH
 * ───────────────────────────────────────────── */
let selected_item_id = input.selected_item_id || input.item_id;

// ✅ Commit-stage integrity check
if (
  input.commit_stage === true &&
  input.item_id !== selected_item_id
) {
  throw new Error(
    `Primary item mismatch at commit stage.
     Selected: ${selected_item_id}
     Current: ${input.item_id}`
  );
}

/* ─────────────────────────────────────────────
 * LOAD CANONICAL ITEM CATALOG
 * ───────────────────────────────────────────── */
const catalogItems = $items("Get item_id")
  .map(i => i.json)
  .filter(r => r.active === true || r.active === "TRUE");

if (!Array.isArray(catalogItems) || catalogItems.length === 0) {
  throw new Error("Item catalog is empty or unavailable");
}

const item = catalogItems.find(
  r => r.item_id === selected_item_id
);

if (!item) {
  throw new Error(`Invalid primary item_id: ${selected_item_id}`);
}

/* ─────────────────────────────────────────────
 * BUILD CANONICAL PRIMARY ITEM
 * ───────────────────────────────────────────── */
const quantity =
  Number.isFinite(Number(input.Quantity)) &&
  Number(input.Quantity) > 0
    ? Number(input.Quantity)
    : 1;

const primary_item = {
  item_id: item.item_id,
  name: item.name,
  description: item.description || "",
  base_price_cents: Math.round(Number(item.base_price) * 100),
  quantity,
};

/* ─────────────────────────────────────────────
 * RETURN AUTHORITATIVE STATE
 * ───────────────────────────────────────────── */
return {
  ...input,

  // ✅ Latched identity
  selected_item_id,

  // ✅ Canonical primary item
  primary_item,

  // ✅ Audit
  primary_item_resolved_at: new Date().toISOString(),
};

/**
ells, modifiers, drinks) * PRIMARY_ITEM_INTEGRITY_GUARD — FINAL
 * from overriding an already-selected primary entrée.
 *
 * Side-only passes are allowed.
 */

const input = $json;

// ✅ Locked primary entrée (if any)
const locked_primary =
  typeof input.selected_item_id === "string"
    ? input.selected_item_id
    : null;

// ✅ Currently submitted item (if any)
const submitted_item =
  typeof input.item_id === "string"
    ? input.item_id
    : null;

// ✅ Guard condition:
// - A primary entrée is already locked
// - A different item_id is submitted
// - Submission is NOT from the primary stage
if (
  locked_primary &&
  submitted_item &&
  submitted_item !== locked_primary &&
  input.order_stage !== "primary"
) {
  throw new Error(
    `PRIMARY_ITEM_INTEGRITY_GUARD:
     Locked primary: ${locked_primary}
     Submitted item: ${submitted_item}
     Stage: ${input.order_stage || "unknown"}`
  );
}

// ✅ Pass through unchanged
return input;

/**
 * CART BUILDER — WORKFLOW 3 SAFE (FINAL, MERGE‑ALIGNED)
 *
 * RESPONSIBILITIES:
 * - Build NEW cart items for this pass only
 * - Compute subtotal for NEW items only
 * - Enforce structural invariants for this pass
 *
 * NON‑RESPONSIBILITIES:
 * - Loading existing cart state
 * - Merging with existing cart_items
 * - Freezing state
 * - Guessing user intent
 */

const input = $json;

/* ─────────────────────────────────────────────
 * 1️⃣ COMMIT GATE
 * ───────────────────────────────────────────── */
if (input.commit_stage !== true) {
  return input;
}

/* ─────────────────────────────────────────────
 * 2️⃣ NORMALIZE INPUTS
 * ───────────────────────────────────────────── */
const primary_item = input.primary_item || null;
const primary_variant = input.primary_variant || null;

const primary_modifiers = Array.isArray(input.primary_modifiers)
  ? input.primary_modifiers
  : [];

const upsell_items = Array.isArray(input.upsell_items)
  ? input.upsell_items
  : [];

/* ✅ CANONICAL NOTES (ITEM‑SCOPED) */
const normalized_notes =
  typeof input.Notes === "string"
    ? input.Notes.trim()
    : "";

/* ─────────────────────────────────────────────
 * 3️⃣ DEFENSIVE INVARIANT
 * ───────────────────────────────────────────── */
if (
  primary_item === null &&
  Array.isArray(input.modifier_ids) &&
  input.modifier_ids.length > 0
) {
  throw new Error(
    "CART_BUILDER_WKFL3: modifiers present without a primary item"
  );
}

/* ─────────────────────────────────────────────
 * 4️⃣ BUILD **NEW** CART ITEMS ONLY
 * ───────────────────────────────────────────── */
const new_cart_items = [];

/* ✅ PRIMARY ITEM (THIS PASS ONLY) */
if (primary_item) {
  const base_price_cents = Math.round(
    Number(primary_item.sell_price ?? primary_item.base_price) * 100
  );

  if (!Number.isInteger(base_price_cents)) {
    throw new Error("CART_BUILDER_WKFL3: primary item missing valid price");
  }

  const modifier_total_cents = primary_modifiers.reduce(
    (sum, m) => sum + Math.round(Number(m.price_delta || 0) * 100),
    0
  );

  const variant_delta_cents =
    primary_variant && typeof primary_variant.price_delta === "number"
      ? Math.round(primary_variant.price_delta * 100)
      : 0;

  const line_total_cents =
    base_price_cents + variant_delta_cents + modifier_total_cents;

  new_cart_items.push({
    type: "primary",
    item_id: primary_item.item_id,
    display_name: primary_item.name,
    quantity: primary_item.quantity ?? 1,
    base_price_cents,
    variant_price_cents: variant_delta_cents,
    modifier_total_cents,
    line_total_cents,
    modifiers: primary_modifiers,

    // ✅ ITEM‑SCOPED NOTES
    notes: normalized_notes,
    origin_pass: input.order_stage || null,
  });
}

/* ✅ UPSELL ITEMS (THIS PASS ONLY) */
upsell_items.forEach(u => {
  if (!u.item || !u.item.item_id) {
    throw new Error(
      "CART_BUILDER_WKFL3: upsell item missing item reference"
    );
  }

  const base_price_cents = Math.round(
    Number(u.item.sell_price ?? u.item.base_price) * 100
  );

  if (!Number.isInteger(base_price_cents)) {
    throw new Error(
      `CART_BUILDER_WKFL3: upsell item ${u.item.item_id} missing valid price`
    );
  }

  const variant_delta_cents =
    u.variant && typeof u.variant.price_delta === "number"
      ? Math.round(u.variant.price_delta * 100)
      : 0;

  const modifiers = Array.isArray(u.modifiers) ? u.modifiers : [];

  const modifier_total_cents = modifiers.reduce(
    (sum, m) => sum + Math.round(Number(m.price_delta || 0) * 100),
    0
  );

  const line_total_cents =
    base_price_cents + variant_delta_cents + modifier_total_cents;

  new_cart_items.push({
    type: "upsell",
    item_id: u.item.item_id,
    display_name: u.item.name,
    quantity: 1,
    base_price_cents,
    variant_price_cents: variant_delta_cents,
    modifier_total_cents,
    line_total_cents,
    modifiers,

    // ✅ ITEM‑SCOPED NOTES (FIX)
    notes: normalized_notes,
    origin_pass: input.order_stage || null,
  });
});

/* ─────────────────────────────────────────────
 * 5️⃣ SUBTOTAL — THIS PASS ONLY
 * ───────────────────────────────────────────── */
const new_subtotal_cents = new_cart_items.reduce(
  (sum, item) => sum + item.line_total_cents,
  0
);

if (!Number.isInteger(new_subtotal_cents) || new_subtotal_cents <= 0) {
  throw new Error("CART_BUILDER_WKFL3: new subtotal must be positive");
}

/* ─────────────────────────────────────────────
 * 6️⃣ FINAL INVARIANTS — THIS PASS
 * ───────────────────────────────────────────── */
const primary_count = new_cart_items.filter(
  i => i.type === "primary"
).length;

if (primary_count > 1) {
  throw new Error("CART_BUILDER_WKFL3: more than one primary item in a pass");
}

new_cart_items.forEach((item, index) => {
  if (!item.display_name) {
    throw new Error(
      `CART_BUILDER_WKFL3: cart item ${index} missing display_name`
    );
  }
  if (!Number.isInteger(item.line_total_cents)) {
    throw new Error(
      `CART_BUILDER_WKFL3: cart item ${index} invalid line_total_cents`
    );
  }
});

/* ─────────────────────────────────────────────
 * ✅ OUTPUT — FOR WKFL3_MERGE_CART_ITEMS
 * ───────────────────────────────────────────── */
return {
  ...input,

  // ✅ DO NOT TOUCH EXISTING cart_items
  new_cart_items,

  // ✅ SUBTOTAL FOR THIS PASS ONLY
  new_subtotal_cents,
};

/**
 * WKFL3_MERGE_CART_ITEMS — AUTHORITATIVE
 *
 * Combines existing cart_items with new_cart_items.
 * NEVER creates or changes cart_id.
 * Enforces item‑scoped invariants.
 */

const input = $json;

/* ─────────────────────────────────────────────
 * 1️⃣ HARD GUARD — IDENTITY
 * ───────────────────────────────────────────── */
if (!input.cart_id) {
  throw new Error("WKFL3_MERGE: missing cart_id (state corruption detected)");
}

/* ─────────────────────────────────────────────
 * 2️⃣ LOAD SOURCE‑OF‑TRUTH INPUTS
 * ───────────────────────────────────────────── */

// ✅ Existing cart (canonical)
const existing = Array.isArray(input.cart_items)
  ? input.cart_items
  : [];

// ✅ New items from this pass
const next = Array.isArray(input.new_cart_items)
  ? input.new_cart_items
  : [];

if (next.length === 0) {
  throw new Error("WKFL3_MERGE: no new items to merge");
}

/* ─────────────────────────────────────────────
 * 3️⃣ MODEL 3 INVARIANT — ITEM‑SCOPED NOTES
 * ───────────────────────────────────────────── */
next.forEach((item, index) => {
  if ("notes" in item && typeof item.notes !== "string") {
    throw new Error(
      `WKFL3_MERGE: new_cart_items[${index}].notes must be a string`
    );
  }
});

/* ─────────────────────────────────────────────
 * 4️⃣ MERGE DETERMINISTICALLY
 * ───────────────────────────────────────────── */
const merged_cart_items = [...existing, ...next];

/* ─────────────────────────────────────────────
 * 5️⃣ RECOMPUTE SUBTOTAL (SOURCE OF TRUTH)
 * ───────────────────────────────────────────── */
const subtotal_cents = merged_cart_items.reduce(
  (sum, item) => sum + item.line_total_cents,
  0
);

if (!Number.isInteger(subtotal_cents) || subtotal_cents <= 0) {
  throw new Error("WKFL3_MERGE: invalid subtotal after merge");
}

/* ─────────────────────────────────────────────
 * ✅ OUTPUT — CANONICAL CART STATE
 * ───────────────────────────────────────────── */
return {
  // ✅ Preserve ALL upstream state explicitly
  ...input,

  // ✅ Canonical cart
  cart_items: merged_cart_items,

  // ✅ Canonical pricing
  subtotal_cents,
};

/**
 * STRUCTURAL_RESOLVE_SIDES_ONLY — CANONICAL
 */

const input = $json;

/* 1️⃣ LOAD CATALOGS */
const ITEMS = $items("Get item_id").map(i => i.json);
const VARIANTS = $items("Get variant_id").map(i => i.json);
const MODIFIERS = $items("Get mod_id").map(i => i.json);

/* 2️⃣ NORMALIZE UPSOLD ITEMS (already merged upstream) */
const incomingIds = Array.isArray(input.upsell_item_ids)
  ? input.upsell_item_ids
  : [];

const upsell_selections =
  typeof input.upsell_selections === "object" && input.upsell_selections
    ? input.upsell_selections
    : {};

/* 3️⃣ RESOLVE UPSELL ITEMS */
const upsell_items = incomingIds.map(item_id => {
  const item = ITEMS.find(
    i =>
      i.item_id === item_id &&
      typeof i.name === "string" &&
      i.sell_price != null
  );

  if (!item) {
    throw new Error(
      `SIDES_ONLY_RESOLVE: item not found or invalid for ${item_id}`
    );
  }

  const selection = upsell_selections[item_id] || {};

  const variant =
    typeof selection.variant_id === "string"
      ? VARIANTS.find(v => v.variant_id === selection.variant_id) || null
      : null;

  const modifiers = Array.isArray(selection.modifier_ids)
    ? selection.modifier_ids
        .map(id => MODIFIERS.find(m => m.mod_id === id) || null)
        .filter(Boolean)
    : [];

  return { item, variant, modifiers };
});

/* ✅ 4️⃣ CANONICALIZE IDS */
const canonicalUpsellIds = upsell_items.map(u => u.item.item_id);

/* 5️⃣ OUTPUT */
return {
  ...input,

  primary_item: null,
  primary_variant: null,
  primary_modifiers: [],

  upsell_item_ids: canonicalUpsellIds,
  upsell_items,

  structure_version: 3
};

const input = $json;

/*
  OUTPUT STRUCTURES — MERGE INTO EXISTING IF PRESENT
*/
const upsell_item_ids = Array.isArray(input.upsell_item_ids)
  ? [...input.upsell_item_ids]
  : [];

const upsell_selections =
  typeof input.upsell_selections === "object" && input.upsell_selections
    ? { ...input.upsell_selections }
    : {};

/*
─────────────────────────────────────────────
HELPERS
─────────────────────────────────────────────
*/
const addUpsellItem = (itemId) => {
  if (!upsell_item_ids.includes(itemId)) {
    upsell_item_ids.push(itemId);
  }
};

/*
─────────────────────────────────────────────
FRIES (PLAIN / LOADED)
─────────────────────────────────────────────
Items, NOT modifiers
*/
const friesValue = input["Plain/Loaded Fries"];
let friesItemId = null;

if (typeof friesValue === "string") {
  if (friesValue.includes("Plain")) friesItemId = "FRIES_PLAIN";
  if (friesValue.includes("Bac'n")) friesItemId = "LOADED_FRIES_BC";
  if (friesValue.toLowerCase().includes("philly chik")) friesItemId = "LOADED_FRIES_PC";
  if (friesValue.toLowerCase().includes("garlic parm")) friesItemId = "LOADED_FRIES_GP";
  if (friesValue.toLowerCase().includes("stek")) friesItemId = "LOADED_FRIES_PS";
}

if (friesItemId) {
  addUpsellItem(friesItemId);

  if (Array.isArray(input["Add Ons"])) {
    upsell_selections[friesItemId] = upsell_selections[friesItemId] || { modifier_ids: [] };

    input["Add Ons"].forEach(label => {
      if (label.includes("Jalap")) upsell_selections[friesItemId].modifier_ids.push("FRIES_ADD_JALAP");
      if (label.includes("Bac")) upsell_selections[friesItemId].modifier_ids.push("FRIES_ADD_BACN");
      if (label.includes("Stek")) upsell_selections[friesItemId].modifier_ids.push("FRIES_ADD_STEK");
      if (label.includes("Chik")) upsell_selections[friesItemId].modifier_ids.push("FRIES_ADD_CHIKN");
    });
  }
}

/*
─────────────────────────────────────────────
SIDE SALAD
─────────────────────────────────────────────
*/
if (input["Greens"]) {
  addUpsellItem("SIDE_SALAD");
}

/*
─────────────────────────────────────────────
COOKIES
─────────────────────────────────────────────
*/
if (input["Sweets"]) {
  addUpsellItem("COOKIES_2");
}

/*
─────────────────────────────────────────────
WATER
─────────────────────────────────────────────
*/
if (input["16 oz Bottled Water"]) {
  addUpsellItem("WATER_16OZ");
}

/*
─────────────────────────────────────────────
JUICE
─────────────────────────────────────────────
*/
if (input["Cold Press Juice"]) {
  let juiceItemId = null;

  if (input["Juice Size"]?.includes("16 oz")) juiceItemId = "JUICE_CP_16";
  if (input["Juice Size"]?.includes("10 oz")) juiceItemId = "JUICE_CP_10";

  if (juiceItemId) {
    addUpsellItem(juiceItemId);

    upsell_selections[juiceItemId] = upsell_selections[juiceItemId] || { modifier_ids: [] };

    if (typeof input["Cold Press Juice"] === "string") {
      if (input["Cold Press Juice"].includes("Green")) upsell_selections[juiceItemId].modifier_ids.push("JFLAV_GREEN");
      if (input["Cold Press Juice"].includes("Orange")) upsell_selections[juiceItemId].modifier_ids.push("JFLAV_ORANGE");
      if (input["Cold Press Juice"].includes("Sweet")) upsell_selections[juiceItemId].modifier_ids.push("JFLAV_SWEET");
    }
  }
}

/*
─────────────────────────────────────────────
FINAL OUTPUT
─────────────────────────────────────────────
*/
return {
  ...input,
  upsell_item_ids,
  upsell_selections,
  item_role: "sides_first"
};

/**
 * FREEZE_CART_STATE — FINAL
 *
 * AUTHORITATIVE LOCK for Model 3 (item‑scoped notes)
 * After this node, cart_items are immutable
 */

const input = $json;

/* ─────────────────────────────────────────────
 * 1️⃣ DOUBLE‑FREEZE GUARD
 * ───────────────────────────────────────────── */
if (input.is_frozen === true) {
  throw new Error("FREEZE_CART_STATE: cart is already frozen");
}

/* ─────────────────────────────────────────────
 * 2️⃣ REQUIRED STATE VALIDATION
 * ───────────────────────────────────────────── */
if (!input.cart_id) {
  throw new Error("FREEZE_CART_STATE: missing cart_id");
}

if (!Array.isArray(input.cart_items) || input.cart_items.length === 0) {
  throw new Error(
    "FREEZE_CART_STATE: cart_items must exist and contain at least one item"
  );
}

if (!Number.isInteger(input.subtotal_cents) || input.subtotal_cents <= 0) {
  throw new Error("FREEZE_CART_STATE: invalid subtotal_cents");
}

if (!Number.isInteger(input.total_cents) || input.total_cents <= 0) {
  throw new Error("FREEZE_CART_STATE: invalid total_cents");
}

/* ─────────────────────────────────────────────
 * 3️⃣ MODEL 3 INVARIANTS — ITEM‑SCOPED NOTES
 * ───────────────────────────────────────────── */
input.cart_items.forEach((item, index) => {
  if ("notes" in item && typeof item.notes !== "string") {
    throw new Error(
      `FREEZE_CART_STATE: cart_items[${index}].notes must be a string`
    );
  }
});

/* ─────────────────────────────────────────────
 * 4️⃣ PASS INDEX OWNERSHIP
 * ───────────────────────────────────────────── */
const pass_index =
  typeof input.pass_index === "number"
    ? input.pass_index
    : 1;

/* ─────────────────────────────────────────────
 * 5️⃣ HARD FREEZE — EMIT CANONICAL PAYLOAD
 * ───────────────────────────────────────────── */
return {
  // 🔒 IDENTITY
  cart_id: input.cart_id,
  G_USER_ID: input.G_USER_ID ?? null,
  customer_name: input.customer_name ?? "",
  customer_email: input.customer_email ?? "",
  customer_phone: input.customer_phone ?? "",

  // ✅ CANONICAL CART (ITEM‑SCOPED NOTES LIVE HERE)
  cart_items: input.cart_items,

  // ✅ FINAL PRICING (READ‑ONLY)
  subtotal_cents: input.subtotal_cents,
  tax_cents: Number.isInteger(input.tax_cents) ? input.tax_cents : 0,
  total_cents: input.total_cents,

  // ✅ FREEZE IDENTITY
  pass_index,
  frozen_pass_index: pass_index,
  is_frozen: true,

  // ℹ️ ORDER‑LEVEL METADATA (NON‑AUTHORITATIVE)
  Notes:
    typeof input.Notes === "string"
      ? input.Notes
      : "",

  submittedAt: input.submittedAt || null,
  formMode: input.formMode || null,
  ordering_pattern: input.ordering_pattern || null,

  // ✅ AUDIT
  freeze_timestamp: new Date().toISOString()
};

const input = $json;

// ─────────────────────────────────────
// Guards
// ─────────────────────────────────────
if (!Array.isArray(input.cart_items)) {
  throw new Error("Tax calculation requires cart_items array");
}

if (typeof input.subtotal_cents !== "number") {
  throw new Error("Tax calculation requires subtotal_cents");
}

// ─────────────────────────────────────
// Tax (Little Rock, AR – Pickup)
// ─────────────────────────────────────
const TAX_RATE_PERCENT = 9.52;
const TAX_RATE_DECIMAL = 0.0952;

const tax_cents = Math.round(input.subtotal_cents * TAX_RATE_DECIMAL);

// ─────────────────────────────────────
// Total
// ─────────────────────────────────────
const total_cents = input.subtotal_cents + tax_cents;

// ─────────────────────────────────────
// Output (canonical)
// ─────────────────────────────────────
return {
  ...input,
  tax_rate_percent: TAX_RATE_PERCENT,
  tax_cents,
  total_cents
};

// ─────────────────────────────────────────────
// 1️⃣ LOAD FULL CATALOGS (EXPLICIT, DETERMINISTIC)
// ─────────────────────────────────────────────
const ITEMS = $items("Get item_id").map(i => i.json);
const VARIANTS = $items("Get variant_id").map(i => i.json);
const MODIFIERS = $items("Get mod_id").map(i => i.json);
const MOD_GROUPS = $items("Get mod_groups").map(i => i.json);

// ─────────────────────────────────────────────
// 2️⃣ READ + NORMALIZE COMMITTED CONTEXT
// IMPORTANT:
// After Merge + Set + commit_stage === true,
// ALL intent (primary + upsell) exists on $json.
// STAGED NODES MUST NOT BE READ HERE.
// ─────────────────────────────────────────────
const primaryRaw = $json;
const upsellRaw = $json; // ✅ FIX — read upsells from canonical payload

// Normalize primary intent
const primary = {
  entree_key:
    typeof primaryRaw.entree_key === "string"
      ? primaryRaw.entree_key
      : null,

  variant_id:
    typeof primaryRaw.variant_id === "string"
      ? primaryRaw.variant_id
      : null,

  modifier_ids:
    Array.isArray(primaryRaw.modifier_ids)
      ? primaryRaw.modifier_ids.filter(x => typeof x === "string")
      : []
};

// Normalize upsell intent
const upsellCtx = {
  upsell_item_ids:
    Array.isArray(upsellRaw.upsell_item_ids)
      ? upsellRaw.upsell_item_ids.filter(x => typeof x === "string")
      : [],

  upsell_selections:
    typeof upsellRaw.upsell_selections === "object" &&
    upsellRaw.upsell_selections !== null
      ? upsellRaw.upsell_selections
      : {}
};

// ─────────────────────────────────────────────
// 3️⃣ HARD VALIDATION — FAIL EARLY
// ─────────────────────────────────────────────
if (!primary.entree_key) {
  throw new Error(
    "STRUCTURAL_RESOLVE_MENU_ROWS: missing primary.entree_key"
  );
}

// ─────────────────────────────────────────────
// 4️⃣ RESOLVE PRIMARY ITEM
// ─────────────────────────────────────────────
const primaryItem = ITEMS.find(
  i =>
    i.item_id === primary.entree_key &&
    typeof i.name === "string" &&
    i.sell_price != null
);

if (!primaryItem) {
  throw new Error(
    `STRUCTURAL_RESOLVE_MENU_ROWS: primary item not found for ${primary.entree_key}`
  );
}

// ─────────────────────────────────────────────
// 5️⃣ RESOLVE PRIMARY VARIANT (OPTIONAL)
// ─────────────────────────────────────────────
const primaryVariant =
  primary.variant_id
    ? VARIANTS.find(v => v.variant_id === primary.variant_id) || null
    : null;

// ─────────────────────────────────────────────
// 6️⃣ RESOLVE PRIMARY MODIFIERS
// ─────────────────────────────────────────────
const primary_modifiers =
  Array.isArray(primary.modifier_ids)
    ? primary.modifier_ids
        .map(id => MODIFIERS.find(m => m.mod_id === id) || null)
        .filter(Boolean)
    : [];

// ─────────────────────────────────────────────
// 7️⃣ RESOLVE UPSELL ITEMS + THEIR MODIFIERS ✅
// (THIS WAS THE MISSING PIECE BEFORE THE FIX)
// ─────────────────────────────────────────────
const upsell_items = upsellCtx.upsell_item_ids.map(upsellItemId => {
  const upsellItem = ITEMS.find(
    i =>
      i.item_id === upsellItemId &&
      typeof i.name === "string" &&
      i.sell_price != null
  );

  if (!upsellItem) {
    throw new Error(
      `STRUCTURAL_RESOLVE_MENU_ROWS: upsell item not found for ${upsellItemId}`
    );
  }

  const selection = upsellCtx.upsell_selections[upsellItemId] || {};

  const variant =
    typeof selection.variant_id === "string"
      ? VARIANTS.find(v => v.variant_id === selection.variant_id) || null
      : null;

  const modifiers =
    Array.isArray(selection.modifier_ids)
      ? selection.modifier_ids
          .map(id => MODIFIERS.find(m => m.mod_id === id) || null)
          .filter(Boolean)
      : [];

  return {
    item: upsellItem,
    variant,
    modifiers
  };
});

// ─────────────────────────────────────────────
// 8️⃣ FINAL CANONICAL OUTPUT
// ─────────────────────────────────────────────
return [
  {
    json: {
      // ✅ Preserve merged execution context
      ...$json,

      // ✅ Fully resolved order structure
      primary_item: primaryItem,
      primary_variant: primaryVariant,
      primary_modifiers,
      upsell_items,

      // ✅ Versioning
      structure_version: 3
    }
  }
];

options.customCss:
/* =========================================================
   Utopia Deli — Accessible, Brand-Consistent Light/Dark CSS
   - Light & Dark tokens
   - OS auto + manual override via [data-theme]
   - Optimized form field readability
   - Safer focus outlines and button states
   ========================================================= */

/* ---------------------------
   0) Base (shared) tokens
   --------------------------- */
:root {
  /* Typography */
  --font-family: 'Open Sans', system-ui, -apple-system, Segoe UI, Roboto, Arial, sans-serif;
  --font-weight-normal: 400;
  --font-weight-bold: 600;
  --font-size-body: 12px;
  --font-size-label: 14px;
  --font-size-test-notice: 12px;
  --font-size-input: 14px;
  --font-size-header: 20px;
  --font-size-paragraph: 14px;
  --font-size-link: 12px;
  --font-size-error: 12px;
  --font-size-html-h1: 28px;
  --font-size-html-h2: 20px;
  --font-size-html-h3: 16px;
  --font-size-html-h4: 14px;
  --font-size-html-h5: 12px;
  --font-size-html-h6: 10px;
  --font-size-subheader: 14px;

  /* Brand */
  --ud-primary: #590B3F;   /* plum (headings, emphasis) */
  --ud-accent:  #AF3D4B;   /* rose (primary CTA) */
  --ud-secondary: #754681; /* violet (focus/interactive) */
  --ud-gold: #D59F5C;      /* gold (notices/highlights) */

  /* Component geometry */
  --border-radius-card: 8px;
  --border-radius-input: 6px;
  --border-radius-clear-btn: 50%;
  --card-border-radius: 8px;

  --padding-container-top: 24px;
  --padding-card: 24px;
  --padding-test-notice-vertical: 12px;
  --padding-test-notice-horizontal: 24px;
  --margin-bottom-card: 16px;
  --padding-form-input: 12px;
  --card-padding: 24px;
  --card-margin-bottom: 16px;

  --container-width: 448px;
  --submit-btn-height: 48px;
  --checkbox-size: 18px;

  --opacity-placeholder: 0.6;

  /* Logo */
  --brand-logo-url: url('https://drive.google.com/uc?export=view&id=1EoM45ce5tUTsZoNdGljYVtjLNQA4XTVI');
  --brand-logo-height: 36px;
  --brand-logo-padding: 8px 0 16px 0;

  /* Elevation */
  --elev-1: 0 4px 16px rgba(17, 24, 39, 0.06); /* light */
  --elev-1-dark: 0 10px 24px rgba(0,0,0,0.35);  /* dark */
}

/* -----------------------------------------
   1) LIGHT THEME TOKENS (default)
   ----------------------------------------- */
:root,
:root[data-theme="light"] {
  --color-background: #FBFCFE;     /* page canvas */
  --color-card-bg: #FFFFFF;        /* card surface */
  --color-card-border: #E5E7EB;    /* outlines/dividers */
  --color-card-shadow: rgba(17,24,39,0.06);

  --color-header: var(--ud-primary);
  --color-header-subtext: #6B7280;

  --color-html-text: #1F2937;      /* darker for body copy */
  --color-label: #374151;
  --color-html-link: var(--ud-accent);

  --color-input-bg: #FFFFFF;
  --color-input-border: #D1D5DB;
  --color-input-text: #111827;     /* deep gray for readability */
  --color-input-placeholder: rgba(55,65,81,0.6);
  --color-focus-border: var(--ud-secondary);
  --focus-ring: 0 0 0 3px rgba(117, 70, 129, 0.18);

  --color-submit-btn-bg: var(--ud-accent);
  --color-submit-btn-text: #FFFFFF;
  --color-secondary-btn-bg: #F3F4F6;
  --color-secondary-btn-text: #1F2937;

  --color-test-notice-text: #6B3506;            /* readable on soft gold */
  --color-test-notice-bg: #FFF8EE;
  --color-test-notice-border: #F3D6A7;

  --color-error: #B91C1C; /* slightly darker than #EA1F30 for contrast */
  --color-required: var(--ud-accent);
}

/* -----------------------------------------
   2) DARK THEME TOKENS (auto + manual)
   ----------------------------------------- */
@media (prefers-color-scheme: dark) {
  :root:not([data-theme="light"]):not([data-theme="hc"]) {
    --color-background: #0F0F12;
    --color-card-bg: #111217;
    --color-card-border: #1F2430;
    --color-card-shadow: rgba(0,0,0,0.4);

    --color-header: #F2E8F0;            /* plum on dark (tint) */
    --color-header-subtext: #A9AFB8;

    --color-html-text: #E6E7EB;
    --color-label: #D3D5DB;
    --color-html-link: #E97B8A;         /* rose tint for dark */

    --color-input-bg: #0F1116;          /* dark field to spare eyes */
    --color-input-border: #2A2F3A;
    --color-input-text: #E6E7EB;        /* ✅ readable in dark fields */
    --color-input-placeholder: rgba(230,231,235,0.55);
    --color-focus-border: #B692C6;      /* violet tint */
    --focus-ring: 0 0 0 3px rgba(182,146,198,0.28);

    --color-submit-btn-bg: #C84B5D;     /* brighter rose for contrast on dark */
    --color-submit-btn-text: #0D0E12;
    --color-secondary-btn-bg: #1D2430;
    --color-secondary-btn-text: #E6E7EB;

    --color-test-notice-text: #F0C98B;  /* gold tint readable on dark */
    --color-test-notice-bg: #201A12;
    --color-test-notice-border: #3A2B18;

    --color-error: #F97066; /* warm error that passes on dark */
    --color-required: #FF9CA8;

    /* Elevation */
    --elev-1: var(--elev-1-dark);
  }
}

/* Manual dark override */
:root[data-theme="dark"] {
  /* Same as media query block above to force dark regardless of OS */
  --color-background: #0F0F12;
  --color-card-bg: #111217;
  --color-card-border: #1F2430;
  --color-card-shadow: rgba(0,0,0,0.4);

  --color-header: #F2E8F0;
  --color-header-subtext: #A9AFB8;

  --color-html-text: #E6E7EB;
  --color-label: #D3D5DB;
  --color-html-link: #E97B8A;

  --color-input-bg: #0F1116;
  --color-input-border: #2A2F3A;
  --color-input-text: #E6E7EB;          /* ✅ fixed */
  --color-input-placeholder: rgba(230,231,235,0.55);
  --color-focus-border: #B692C6;
  --focus-ring: 0 0 0 3px rgba(182,146,198,0.28);

  --color-submit-btn-bg: #C84B5D;
  --color-submit-btn-text: #0D0E12;
  --color-secondary-btn-bg: #1D2430;
  --color-secondary-btn-text: #E6E7EB;

  --color-test-notice-text: #F0C98B;
  --color-test-notice-bg: #201A12;
  --color-test-notice-border: #3A2B18;

  --color-error: #F97066;
  --color-required: #FF9CA8;

  --elev-1: var(--elev-1-dark);
}

/* -----------------------------------------
   3) Optional High-Contrast Theme
   ----------------------------------------- */
:root[data-theme="hc"] {
  --color-background: #0B0B0D;
  --color-card-bg: #0F0F12;
  --color-card-border: #323743;

  --color-header: #FFFFFF;
  --color-header-subtext: #CBD2D9;

  --color-html-text: #FFFFFF;
  --color-label: #FFFFFF;
  --color-html-link: #FF89A0;

  --color-input-bg: #0B0C10;
  --color-input-border: #4A5160;
  --color-input-text: #FFFFFF;
  --color-input-placeholder: rgba(255,255,255,0.6);
  --color-focus-border: #FFD166;
  --focus-ring: 0 0 0 3px rgba(255,209,102,0.45);

  --color-submit-btn-bg: #FF5C74;
  --color-submit-btn-text: #0D0E12;
  --color-secondary-btn-bg: #1C2230;
  --color-secondary-btn-text: #FFFFFF;

  --color-test-notice-text: #FFD166;
  --color-test-notice-bg: #1A1208;
  --color-test-notice-border: #6B4E1B;

  --color-error: #FF6B6B;
  --color-required: #FF9CA8;

  --elev-1: var(--elev-1-dark);
}

/* -----------------------------------------
   4) Structure & Components (shared)
   ----------------------------------------- */
.ud-container {
  max-width: var(--container-width);
  margin: 0 auto;
  padding: var(--padding-container-top) 16px 32px;
  font-family: var(--font-family);
  color: var(--color-html-text);
  background: var(--color-background);
}

.ud-card {
  background: var(--color-card-bg);
  border: 1px solid var(--color-card-border);
  border-radius: var(--card-border-radius);
  padding: var(--card-padding);
  box-shadow: var(--elev-1);
  margin-bottom: var(--card-margin-bottom);
}

.ud-header {
  display: block;
  padding: var(--brand-logo-padding);
  border-bottom: 1px solid var(--color-card-border);
  color: var(--color-header);
  position: relative;
  min-height: calc(var(--brand-logo-height) + 16px);
  background-image: var(--brand-logo-url);
  background-repeat: no-repeat;
  background-position: left center;
  background-size: auto var(--brand-logo-height);
  padding-left: calc(var(--brand-logo-height) + 16px);
}
.ud-header h1 {
  margin: 0;
  font-size: var(--font-size-header);
  font-weight: var(--font-weight-bold);
  color: var(--color-header);
}
.ud-header .subtitle {
  margin-top: 4px;
  font-size: var(--font-size-subheader);
  color: var(--color-header-subtext);
}

/* Forms */
.ud-form-group { margin-top: 14px; }
.ud-label {
  display: inline-block;
  margin-bottom: 6px;
  font-size: var(--font-size-label);
  color: var(--color-label);
}

.ud-input,
.ud-select,
.ud-textarea {
  width: 100%;
  border: 1px solid var(--color-input-border);
  border-radius: var(--border-radius-input);
  padding: var(--padding-form-input);
  font-size: var(--font-size-input);
  color: var(--color-input-text);
  background: var(--color-input-bg);
  outline: none;
  transition: border-color 120ms ease, box-shadow 120ms ease, background-color 120ms ease, color 120ms ease;
}
.ud-input::placeholder,
.ud-textarea::placeholder {
  color: var(--color-input-placeholder);
  opacity: 1; /* we control via color token */
}
.ud-input:focus,
.ud-select:focus,
.ud-textarea:focus {
  border-color: var(--color-focus-border);
  box-shadow: var(--focus-ring);
}

.ud-checkrow {
  display: flex;
  align-items: center;
  gap: 8px;
  margin-top: 10px;
  font-size: var(--font-size-body);
  color: var(--color-html-text);
}
.ud-checkbox,
.ud-radio {
  width: var(--checkbox-size);
  height: var(--checkbox-size);
  accent-color: var(--ud-accent); /* native color for inputs */
}

/* Help, errors, required */
.ud-help {
  font-size: var(--font-size-body);
  color: var(--color-header-subtext);
  margin-top: 6px;
}
.ud-error {
  font-size: var(--font-size-error);
  color: var(--color-error);
  margin-top: 6px;
}
.ud-required { color: var(--color-required); }

/* Buttons */
.ud-actions {
  margin-top: 18px;
  display: flex;
  gap: 12px;
}
.ud-btn {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  height: var(--submit-btn-height);
  padding: 0 16px;
  border-radius: 8px;
  border: none;
  font-weight: var(--font-weight-bold);
  cursor: pointer;
  transition: background-color 120ms ease, transform 50ms ease, color 120ms ease, box-shadow 120ms ease;
}
.ud-btn-primary {
  background: var(--color-submit-btn-bg);
  color: var(--color-submit-btn-text);
}
.ud-btn-primary:hover { filter: brightness(0.95); }
.ud-btn-primary:active { transform: translateY(1px); }
.ud-btn-primary:focus-visible { box-shadow: var(--focus-ring); outline: none; }

.ud-btn-secondary {
  background: var(--color-secondary-btn-bg);
  color: var(--color-secondary-btn-text);
}
.ud-btn-secondary:hover { filter: brightness(1.05); }
.ud-btn-secondary:active { transform: translateY(1px); }
.ud-btn-secondary:focus-visible { box-shadow: var(--focus-ring); outline: none; }

/* Links */
.ud-link {
  color: var(--color-html-link);
  text-decoration: underline;
}
.ud-link:hover { filter: brightness(0.95); }

/* Notices */
.ud-notice {
  margin-top: 14px;
  padding: var(--padding-test-notice-vertical) var(--padding-test-notice-horizontal);
  border: 1px solid var(--color-test-notice-border);
  background: var(--color-test-notice-bg);
  color: var(--color-test-notice-text);
  border-radius: 6px;
}

/* Responsive nicety */
@media (max-width: 480px) {
  .ud-container { padding: 16px; }
  .ud-header { padding-left: calc(var(--brand-logo-height) + 12px); }
}

/* Utility: force theme (optional)
   html[data-theme="dark"] .ud-container { ... }  // already handled via tokens
*/

