/* =========================================================
   Utopia Deli — Accessible, Brand-Consistent Light/Dark CSS
   - Light & Dark tokens
   - OS auto + manual override via [data-theme]
   - Optimized form field readability
   - Safer focus outlines and button states
   ========================================================= */

/* ---------------------------
   0) Base (shared) tokens
   --------------------------- */
:root {
  /* Typography */
  --font-family: 'Open Sans', system-ui, -apple-system, Segoe UI, Roboto, Arial, sans-serif;
  --font-weight-normal: 400;
  --font-weight-bold: 600;
  --font-size-body: 12px;
  --font-size-label: 14px;
  --font-size-test-notice: 12px;
  --font-size-input: 14px;
  --font-size-header: 20px;
  --font-size-paragraph: 14px;
  --font-size-link: 12px;
  --font-size-error: 12px;
  --font-size-html-h1: 28px;
  --font-size-html-h2: 20px;
  --font-size-html-h3: 16px;
  --font-size-html-h4: 14px;
  --font-size-html-h5: 12px;
  --font-size-html-h6: 10px;
  --font-size-subheader: 14px;

  /* Brand */
  --ud-primary: #590B3F;   /* plum (headings, emphasis) */
  --ud-accent:  #AF3D4B;   /* rose (primary CTA) */
  --ud-secondary: #754681; /* violet (focus/interactive) */
  --ud-gold: #D59F5C;      /* gold (notices/highlights) */

  /* Component geometry */
  --border-radius-card: 8px;
  --border-radius-input: 6px;
  --border-radius-clear-btn: 50%;
  --card-border-radius: 8px;

  --padding-container-top: 24px;
  --padding-card: 24px;
  --padding-test-notice-vertical: 12px;
  --padding-test-notice-horizontal: 24px;
  --margin-bottom-card: 16px;
  --padding-form-input: 12px;
  --card-padding: 24px;
  --card-margin-bottom: 16px;

  --container-width: 448px;
  --submit-btn-height: 48px;
  --checkbox-size: 18px;

  --opacity-placeholder: 0.6;

  /* Logo */
  --brand-logo-url: url('https://drive.google.com/uc?export=view&id=1EoM45ce5tUTsZoNdGljYVtjLNQA4XTVI');
  --brand-logo-height: 36px;
  --brand-logo-padding: 8px 0 16px 0;

  /* Elevation */
  --elev-1: 0 4px 16px rgba(17, 24, 39, 0.06); /* light */
  --elev-1-dark: 0 10px 24px rgba(0,0,0,0.35);  /* dark */
}

/* -----------------------------------------
   1) LIGHT THEME TOKENS (default)
   ----------------------------------------- */
:root,
:root[data-theme="light"] {
  --color-background: #FBFCFE;     /* page canvas */
  --color-card-bg: #FFFFFF;        /* card surface */
  --color-card-border: #E5E7EB;    /* outlines/dividers */
  --color-card-shadow: rgba(17,24,39,0.06);

  --color-header: var(--ud-primary);
  --color-header-subtext: #6B7280;

  --color-html-text: #1F2937;      /* darker for body copy */
  --color-label: #374151;
  --color-html-link: var(--ud-accent);

  --color-input-bg: #FFFFFF;
  --color-input-border: #D1D5DB;
  --color-input-text: #111827;     /* deep gray for readability */
  --color-input-placeholder: rgba(55,65,81,0.6);
  --color-focus-border: var(--ud-secondary);
  --focus-ring: 0 0 0 3px rgba(117, 70, 129, 0.18);

  --color-submit-btn-bg: var(--ud-accent);
  --color-submit-btn-text: #FFFFFF;
  --color-secondary-btn-bg: #F3F4F6;
  --color-secondary-btn-text: #1F2937;

  --color-test-notice-text: #6B3506;            /* readable on soft gold */
  --color-test-notice-bg: #FFF8EE;
  --color-test-notice-border: #F3D6A7;

  --color-error: #B91C1C; /* slightly darker than #EA1F30 for contrast */
  --color-required: var(--ud-accent);
}

/* -----------------------------------------
   2) DARK THEME TOKENS (auto + manual)
   ----------------------------------------- */
@media (prefers-color-scheme: dark) {
  :root:not([data-theme="light"]):not([data-theme="hc"]) {
    --color-background: #0F0F12;
    --color-card-bg: #111217;
    --color-card-border: #1F2430;
    --color-card-shadow: rgba(0,0,0,0.4);

    --color-header: #F2E8F0;            /* plum on dark (tint) */
    --color-header-subtext: #A9AFB8;

    --color-html-text: #E6E7EB;
    --color-label: #D3D5DB;
    --color-html-link: #E97B8A;         /* rose tint for dark */

    --color-input-bg: #0F1116;          /* dark field to spare eyes */
    --color-input-border: #2A2F3A;
    --color-input-text: #E6E7EB;        /* ✅ readable in dark fields */
    --color-input-placeholder: rgba(230,231,235,0.55);
    --color-focus-border: #B692C6;      /* violet tint */
    --focus-ring: 0 0 0 3px rgba(182,146,198,0.28);

    --color-submit-btn-bg: #C84B5D;     /* brighter rose for contrast on dark */
    --color-submit-btn-text: #0D0E12;
    --color-secondary-btn-bg: #1D2430;
    --color-secondary-btn-text: #E6E7EB;

    --color-test-notice-text: #F0C98B;  /* gold tint readable on dark */
    --color-test-notice-bg: #201A12;
    --color-test-notice-border: #3A2B18;

    --color-error: #F97066; /* warm error that passes on dark */
    --color-required: #FF9CA8;

    /* Elevation */
    --elev-1: var(--elev-1-dark);
  }
}

/* Manual dark override */
:root[data-theme="dark"] {
  /* Same as media query block above to force dark regardless of OS */
  --color-background: #0F0F12;
  --color-card-bg: #111217;
  --color-card-border: #1F2430;
  --color-card-shadow: rgba(0,0,0,0.4);

  --color-header: #F2E8F0;
  --color-header-subtext: #A9AFB8;

  --color-html-text: #E6E7EB;
  --color-label: #D3D5DB;
  --color-html-link: #E97B8A;

  --color-input-bg: #0F1116;
  --color-input-border: #2A2F3A;
  --color-input-text: #E6E7EB;          /* ✅ fixed */
  --color-input-placeholder: rgba(230,231,235,0.55);
  --color-focus-border: #B692C6;
  --focus-ring: 0 0 0 3px rgba(182,146,198,0.28);

  --color-submit-btn-bg: #C84B5D;
  --color-submit-btn-text: #0D0E12;
  --color-secondary-btn-bg: #1D2430;
  --color-secondary-btn-text: #E6E7EB;

  --color-test-notice-text: #F0C98B;
  --color-test-notice-bg: #201A12;
  --color-test-notice-border: #3A2B18;

  --color-error: #F97066;
  --color-required: #FF9CA8;

  --elev-1: var(--elev-1-dark);
}

/* -----------------------------------------
   3) Optional High-Contrast Theme
   ----------------------------------------- */
:root[data-theme="hc"] {
  --color-background: #0B0B0D;
  --color-card-bg: #0F0F12;
  --color-card-border: #323743;

  --color-header: #FFFFFF;
  --color-header-subtext: #CBD2D9;

  --color-html-text: #FFFFFF;
  --color-label: #FFFFFF;
  --color-html-link: #FF89A0;

  --color-input-bg: #0B0C10;
  --color-input-border: #4A5160;
  --color-input-text: #FFFFFF;
  --color-input-placeholder: rgba(255,255,255,0.6);
  --color-focus-border: #FFD166;
  --focus-ring: 0 0 0 3px rgba(255,209,102,0.45);

  --color-submit-btn-bg: #FF5C74;
  --color-submit-btn-text: #0D0E12;
  --color-secondary-btn-bg: #1C2230;
  --color-secondary-btn-text: #FFFFFF;

  --color-test-notice-text: #FFD166;
  --color-test-notice-bg: #1A1208;
  --color-test-notice-border: #6B4E1B;

  --color-error: #FF6B6B;
  --color-required: #FF9CA8;

  --elev-1: var(--elev-1-dark);
}

/* -----------------------------------------
   4) Structure & Components (shared)
   ----------------------------------------- */
.ud-container {
  max-width: var(--container-width);
  margin: 0 auto;
  padding: var(--padding-container-top) 16px 32px;
  font-family: var(--font-family);
  color: var(--color-html-text);
  background: var(--color-background);
}

.ud-card {
  background: var(--color-card-bg);
  border: 1px solid var(--color-card-border);
  border-radius: var(--card-border-radius);
  padding: var(--card-padding);
  box-shadow: var(--elev-1);
  margin-bottom: var(--card-margin-bottom);
}

.ud-header {
  display: block;
  padding: var(--brand-logo-padding);
  border-bottom: 1px solid var(--color-card-border);
  color: var(--color-header);
  position: relative;
  min-height: calc(var(--brand-logo-height) + 16px);
  background-image: var(--brand-logo-url);
  background-repeat: no-repeat;
  background-position: left center;
  background-size: auto var(--brand-logo-height);
  padding-left: calc(var(--brand-logo-height) + 16px);
}
.ud-header h1 {
  margin: 0;
  font-size: var(--font-size-header);
  font-weight: var(--font-weight-bold);
  color: var(--color-header);
}
.ud-header .subtitle {
  margin-top: 4px;
  font-size: var(--font-size-subheader);
  color: var(--color-header-subtext);
}

/* Forms */
.ud-form-group { margin-top: 14px; }
.ud-label {
  display: inline-block;
  margin-bottom: 6px;
  font-size: var(--font-size-label);
  color: var(--color-label);
}

.ud-input,
.ud-select,
.ud-textarea {
  width: 100%;
  border: 1px solid var(--color-input-border);
  border-radius: var(--border-radius-input);
  padding: var(--padding-form-input);
  font-size: var(--font-size-input);
  color: var(--color-input-text);
  background: var(--color-input-bg);
  outline: none;
  transition: border-color 120ms ease, box-shadow 120ms ease, background-color 120ms ease, color 120ms ease;
}
.ud-input::placeholder,
.ud-textarea::placeholder {
  color: var(--color-input-placeholder);
  opacity: 1; /* we control via color token */
}
.ud-input:focus,
.ud-select:focus,
.ud-textarea:focus {
  border-color: var(--color-focus-border);
  box-shadow: var(--focus-ring);
}

.ud-checkrow {
  display: flex;
  align-items: center;
  gap: 8px;
  margin-top: 10px;
  font-size: var(--font-size-body);
  color: var(--color-html-text);
}
.ud-checkbox,
.ud-radio {
  width: var(--checkbox-size);
  height: var(--checkbox-size);
  accent-color: var(--ud-accent); /* native color for inputs */
}

/* Help, errors, required */
.ud-help {
  font-size: var(--font-size-body);
  color: var(--color-header-subtext);
  margin-top: 6px;
}
.ud-error {
  font-size: var(--font-size-error);
  color: var(--color-error);
  margin-top: 6px;
}
.ud-required { color: var(--color-required); }

/* Buttons */
.ud-actions {
  margin-top: 18px;
  display: flex;
  gap: 12px;
}
.ud-btn {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  height: var(--submit-btn-height);
  padding: 0 16px;
  border-radius: 8px;
  border: none;
  font-weight: var(--font-weight-bold);
  cursor: pointer;
  transition: background-color 120ms ease, transform 50ms ease, color 120ms ease, box-shadow 120ms ease;
}
.ud-btn-primary {
  background: var(--color-submit-btn-bg);
  color: var(--color-submit-btn-text);
}
.ud-btn-primary:hover { filter: brightness(0.95); }
.ud-btn-primary:active { transform: translateY(1px); }
.ud-btn-primary:focus-visible { box-shadow: var(--focus-ring); outline: none; }

.ud-btn-secondary {
  background: var(--color-secondary-btn-bg);
  color: var(--color-secondary-btn-text);
}
.ud-btn-secondary:hover { filter: brightness(1.05); }
.ud-btn-secondary:active { transform: translateY(1px); }
.ud-btn-secondary:focus-visible { box-shadow: var(--focus-ring); outline: none; }

/* Links */
.ud-link {
  color: var(--color-html-link);
  text-decoration: underline;
}
.ud-link:hover { filter: brightness(0.95); }

/* Notices */
.ud-notice {
  margin-top: 14px;
  padding: var(--padding-test-notice-vertical) var(--padding-test-notice-horizontal);
  border: 1px solid var(--color-test-notice-border);
  background: var(--color-test-notice-bg);
  color: var(--color-test-notice-text);
  border-radius: 6px;
}

/* Responsive nicety */
@media (max-width: 480px) {
  .ud-container { padding: 16px; }
  .ud-header { padding-left: calc(var(--brand-logo-height) + 12px); }
}

