const input = $json;

/*
  OUTPUT STRUCTURES
*/
const upsell_item_ids = [];
const upsell_selections = {};

/*
─────────────────────────────────────────────
HELPERS
─────────────────────────────────────────────
*/
const addUpsellItem = (itemId) => {
  if (!upsell_item_ids.includes(itemId)) {
    upsell_item_ids.push(itemId);
  }
};

/*
─────────────────────────────────────────────
FRIES (PLAIN / LOADED)
─────────────────────────────────────────────
Items, NOT modifiers
*/
const friesValue = input["Plain/Loaded Fries"];
let friesItemId = null;

if (typeof friesValue === "string") {
  if (friesValue.includes("Plain")) friesItemId = "FRIES_PLAIN";
  if (friesValue.includes("Bac'n")) friesItemId = "LOADED_FRIES_BC";
  if (friesValue.toLowerCase().includes("philly chik")) friesItemId = "LOADED_FRIES_PC";
  if (friesValue.toLowerCase().includes("garlic parm")) friesItemId = "LOADED_FRIES_GP";
  if (friesValue.toLowerCase().includes("stek")) friesItemId = "LOADED_FRIES_PS";
}

if (friesItemId) {
  addUpsellItem(friesItemId);

  // Fries modifiers (only if loaded fries)
  if (Array.isArray(input["Add Ons"])) {
    upsell_selections[friesItemId] = { modifier_ids: [] };

    input["Add Ons"].forEach(label => {
      if (label.includes("Jalap")) upsell_selections[friesItemId].modifier_ids.push("FRIES_ADD_JALAP");
      if (label.includes("Bac")) upsell_selections[friesItemId].modifier_ids.push("FRIES_ADD_BACN");
      if (label.includes("Stek")) upsell_selections[friesItemId].modifier_ids.push("FRIES_ADD_STEK");
      if (label.includes("Chik")) upsell_selections[friesItemId].modifier_ids.push("FRIES_ADD_CHIKN");
    });
  }
}

/*
─────────────────────────────────────────────
SIDE SALAD
─────────────────────────────────────────────
*/
if (input["Greens"]) {
  addUpsellItem("SIDE_SALAD");
}

/*
─────────────────────────────────────────────
COOKIES
─────────────────────────────────────────────
*/
if (input["Sweets"]) {
  addUpsellItem("COOKIES_2");
}

/*
─────────────────────────────────────────────
WATER
─────────────────────────────────────────────
*/
if (input["16 oz Bottled Water"]) {
  addUpsellItem("WATER_16OZ");
}

/*
─────────────────────────────────────────────
JUICE
─────────────────────────────────────────────
Items selected by SIZE, flavor is a modifier
─────────────────────────────────────────────
*/
if (input["Cold Press Juice"]) {
  let juiceItemId = null;

  if (input["Juice Size"]?.includes("16 oz")) juiceItemId = "JUICE_CP_16";
  if (input["Juice Size"]?.includes("10 oz")) juiceItemId = "JUICE_CP_10";

  if (juiceItemId) {
    addUpsellItem(juiceItemId);

    upsell_selections[juiceItemId] = {
      modifier_ids: []
    };

    // Flavor modifiers
    if (typeof input["Cold Press Juice"] === "string") {
      if (input["Cold Press Juice"].includes("Green")) upsell_selections[juiceItemId].modifier_ids.push("JFLAV_GREEN");
      if (input["Cold Press Juice"].includes("Orange")) upsell_selections[juiceItemId].modifier_ids.push("JFLAV_ORANGE");
      if (input["Cold Press Juice"].includes("Sweet")) upsell_selections[juiceItemId].modifier_ids.push("JFLAV_SWEET");
    }
  }
}

/*
─────────────────────────────────────────────
FINAL OUTPUT
─────────────────────────────────────────────
*/
return {
  ...input,
  upsell_item_ids,
  upsell_selections,
  item_role: upsell_item_ids.length > 0 ? "upsell" : input.item_role || null
};

const input = $json;

// Load modifier rows from sheet
const rows = $items("Get mod_id").map(i => i.json);

/* ─────────────────────────────────────────────
 * NORMALIZER (FORMAT‑SAFE, MEANING‑PRESERVING)
 * ───────────────────────────────────────────── */
function normalize(label) {
  return String(label || "")
    .replace(/\+\$[0-9.]+/g, "")     // remove +$price from UI
    .replace(/[’‘]/g, "'")           // normalize apostrophes
    .replace(/[“”]/g, '"')           // normalize quotes
    .replace(/\s+[-–—]\s+/g, " — ")  // normalize dash spacing
    .replace(/\s+/g, " ")            // collapse whitespace
    .trim()
    .toLowerCase();
}

/* ─────────────────────────────────────────────
 * BUILD LOOKUP: normalized mod_name → mod_id
 * ───────────────────────────────────────────── */
const NAME_TO_MOD_ID = {};

rows.forEach(r => {
  if (
    (r.active === true || r.active === "TRUE") &&
    r.mod_id &&
    r.mod_name
  ) {
    const key = normalize(r.mod_name);
    NAME_TO_MOD_ID[key] = r.mod_id;
  }
});

/* ─────────────────────────────────────────────
 * COLLECT ALL MODIFIER FIELDS FROM FORM INPUT
 * ─────────────────────────────────────────────
 * Rule:
 * - Any field whose value is a string or string[]
 *   and matches a known modifier label is valid
 * - We DO NOT care which item it belongs to here
 */
const modifier_ids = [];

Object.keys(input).forEach(fieldName => {
  const raw = input[fieldName];
  if (!raw) return;

  const values = Array.isArray(raw) ? raw : [raw];

  values.forEach(label => {
    const key = normalize(label);
    const mod_id = NAME_TO_MOD_ID[key];

    if (mod_id) {
      modifier_ids.push(mod_id);
    }
  });
});

/* ─────────────────────────────────────────────
 * DEDUPE + OUTPUT
 * ───────────────────────────────────────────── */
return {
  ...input,
  modifier_ids: [...new Set(modifier_ids)]
};

